package com.supermarket;

import org.mybatis.spring.annotation.MapperScan;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

/**
 * 超市前台销售系统 — Spring Boot 启动类
 * <p>
 * 技术栈：Spring Boot 3.4.5 + MyBatis 3.0.4 + MySQL 8.0
 * 架构：Controller → Service → ServiceImpl → Mapper/XML → Entity 五层分层
 * 前端：原生 HTML + CSS + JavaScript (Ajax)，无前端框架依赖
 * </p>
 *
 * @author 常建航
 * @version 1.0
 */
@SpringBootApplication
@MapperScan("com.supermarket.mapper")  // 自动扫描 Mapper 接口并注册为 Spring Bean
public class SupermarketApplication {
    public static void main(String[] args) {
        SpringApplication.run(SupermarketApplication.class, args);
    }
}

package com.supermarket.controller;

import com.supermarket.common.ResultVo;
import com.supermarket.entity.SalesDetail;
import com.supermarket.entity.SalesOrder;
import com.supermarket.entity.SysUser;
import com.supermarket.service.SalesService;
import com.supermarket.service.SysUserService;
import org.springframework.web.bind.annotation.*;

import org.springframework.beans.factory.annotation.Autowired;
import java.util.List;
import java.util.Map;

/**
 * 销售 Controller — 收银下单、订单查询、销售报表、退款
 * <p>
 * 提供前端 Ajax 调用的 RESTful API：
 * - POST /api/sales/submit      提交订单（事务保护）
 * - GET  /api/sales/page        订单分页（联表 sys_user）
 * - GET  /api/sales/detail/{id} 订单详情（联表 sales_detail）
 * - GET  /api/sales/today-summary 今日销售汇总
 * - GET  /api/sales/report        销售日报（查询视图 v_sales_summary）
 * - POST /api/sales/refund/{id}   退款
 * </p>
 */
@RestController
@RequestMapping("/api/sales")
public class SalesController {

    @Autowired
    private SalesService salesService;
    @Autowired
    private SysUserService sysUserService;

    /**
     * 提交销售订单
     * <p>
     * 请求体 JSON 格式：
     * { items: [{productId, quantity}], paidAmount, discountAmount, paymentMethod }
     * </p>
     */
    @PostMapping("/submit")
    public ResultVo<?> submit(@RequestBody Map<String, Object> params) {
        SysUser user = sysUserService.getLoginUser();
        if (user == null) {
            return ResultVo.error(401, "未登录");
        }

        // 解析订单信息
        SalesOrder order = new SalesOrder();
        order.setUserId(user.getUserId());
        if (params.get("paidAmount") != null) {
            order.setPaidAmount(new java.math.BigDecimal(params.get("paidAmount").toString()));
        }
        if (params.get("discountAmount") != null) {
            order.setDiscountAmount(new java.math.BigDecimal(params.get("discountAmount").toString()));
        }
        if (params.get("paymentMethod") != null) {
            order.setPaymentMethod(Integer.parseInt(params.get("paymentMethod").toString()));
        } else {
            order.setPaymentMethod(1);  // 默认现金
        }
        if (params.get("remark") != null) {
            order.setRemark((String) params.get("remark"));
        }

        // 解析明细列表
        @SuppressWarnings("unchecked")
        List<Map<String, Object>> items = (List<Map<String, Object>>) params.get("items");
        java.util.List<SalesDetail> details = new java.util.ArrayList<>();
        for (Map<String, Object> item : items) {
            SalesDetail detail = new SalesDetail();
            detail.setProductId(Integer.parseInt(item.get("productId").toString()));
            detail.setQuantity(Integer.parseInt(item.get("quantity").toString()));
            details.add(detail);
        }

        Map<String, Object> result = salesService.submitOrder(order, details);
        if ((Boolean) result.get("success")) {
            return ResultVo.success((String) result.get("msg"), result);
        }
        return ResultVo.error((String) result.get("msg"));
    }

    /**
     * 订单分页查询（支持按订单号搜索）
     */
    @GetMapping("/page")
    public ResultVo<Map<String, Object>> page(
            @RequestParam(defaultValue = "") String keyword,
            @RequestParam(defaultValue = "1") Integer page,
            @RequestParam(defaultValue = "10") Integer limit) {
        return ResultVo.success(salesService.getOrderPage(keyword, page, limit));
    }

    /**
     * 订单详情：返回订单主记录 + 所有明细行
     */
    @GetMapping("/detail/{id}")
    public ResultVo<Map<String, Object>> detail(@PathVariable Integer id) {
        return ResultVo.success(salesService.getOrderDetail(id));
    }

    /**
     * 今日销售汇总：订单数 + 实收总额（仅含已完成订单）
     */
    @GetMapping("/today-summary")
    public ResultVo<Map<String, Object>> todaySummary() {
        return ResultVo.success(salesService.getTodaySummary());
    }

    /**
     * 销售日报：查询视图 v_sales_summary（按天聚合的销售数据）
     */
    @GetMapping("/report")
    public ResultVo<List<Map<String, Object>>> report() {
        return ResultVo.success(salesService.getSalesReport());
    }

    /**
     * 退款：将订单状态改为"已退款"（order_status=2）
     */
    @PostMapping("/refund/{id}")
    public ResultVo<?> refund(@PathVariable Integer id) {
        boolean ok = salesService.refund(id);
        if (ok) {
            return ResultVo.success("退款成功", null);
        }
        return ResultVo.error("退款失败：订单不存在或已退款");
    }
}

package com.supermarket.controller;

import com.supermarket.common.ResultVo;
import com.supermarket.entity.SysUser;
import com.supermarket.service.SysUserService;
import org.springframework.web.bind.annotation.*;

import org.springframework.beans.factory.annotation.Autowired;
import java.util.Map;

/**
 * 用户 Controller — 处理登录、注册、退出、修改密码
 * <p>
 * 登录成功后用户信息存入 HttpSession，后续请求通过 getLoginUser() 校验身份。
 * </p>
 */
@RestController
@RequestMapping("/api/user")
public class SysUserController {

    @Autowired
    private SysUserService sysUserService;

    /**
     * 登录：验证用户名密码，成功后将用户存入 Session
     */
    @PostMapping("/login")
    public ResultVo<?> login(@RequestBody Map<String, String> params) {
        String username = params.get("username");
        String password = params.get("password");
        if (username == null || password == null || username.isEmpty() || password.isEmpty()) {
            return ResultVo.error("用户名和密码不能为空");
        }
        Map<String, Object> result = sysUserService.login(username, password);
        if ((Boolean) result.get("success")) {
            return ResultVo.success("登录成功", result.get("user"));
        }
        return ResultVo.error((String) result.get("msg"));
    }

    /**
     * 注册：校验用户名唯一性后创建新用户
     */
    @PostMapping("/register")
    public ResultVo<?> register(@RequestBody SysUser user) {
        if (user.getUsername() == null || user.getPassword() == null) {
            return ResultVo.error("用户名和密码不能为空");
        }
        boolean success = sysUserService.register(user);
        if (success) {
            return ResultVo.success("注册成功", null);
        }
        return ResultVo.error("用户名已存在");
    }

    /**
     * 获取当前登录用户（从 Session 读取）
     */
    @GetMapping("/current")
    public ResultVo<SysUser> current() {
        SysUser user = sysUserService.getLoginUser();
        if (user == null) {
            return ResultVo.error(401, "未登录");
        }
        return ResultVo.success(user);
    }

    /**
     * 退出登录：清除 Session
     */
    @PostMapping("/logout")
    public ResultVo<?> logout() {
        sysUserService.logout();
        return ResultVo.success("已退出", null);
    }

    /**
     * 修改密码：需提供原密码验证
     */
    @PostMapping("/password")
    public ResultVo<?> updatePassword(@RequestBody Map<String, String> params) {
        SysUser user = sysUserService.getLoginUser();
        if (user == null) {
            return ResultVo.error(401, "未登录");
        }
        boolean success = sysUserService.updatePassword(
                user.getUserId(),
                params.get("oldPassword"),
                params.get("newPassword"));
        if (success) {
            return ResultVo.success("密码修改成功", null);
        }
        return ResultVo.error("原密码错误");
    }
}

package com.supermarket.entity;

import java.math.BigDecimal;

/**
 * 销售订单实体 — 映射 sales_order 表
 * <p>
 * - orderNo: SO+yyyyMMddHHmmss
 * - paymentMethod: 1=现金 2=微信 3=支付宝
 * - orderStatus: 1=已完成 2=已退款
 * - realName/detailCount: 联表填充，不存库
 * </p>
 */
public class SalesOrder {
    private Integer orderId;
    private String orderNo;          // 订单编号（自动生成）
    private Integer userId;          // 收银员ID
    private BigDecimal totalAmount;  // 订单总金额
    private BigDecimal discountAmount; // 折扣金额
    private BigDecimal paidAmount;   // 实收金额
    private BigDecimal changeAmount; // 找零金额
    private Integer paymentMethod;   // 支付方式：1现金 2微信 3支付宝
    private Integer orderStatus;     // 订单状态：1已完成 2已退货
    private String remark;
    private String createTime;

    // 联表查询用
    private String realName;         // 收银员姓名
    private Integer detailCount;     // 商品种类数

    public SalesOrder() {}

    public Integer getOrderId() { return orderId; }
    public void setOrderId(Integer orderId) { this.orderId = orderId; }
    public String getOrderNo() { return orderNo; }
    public void setOrderNo(String orderNo) { this.orderNo = orderNo; }
    public Integer getUserId() { return userId; }
    public void setUserId(Integer userId) { this.userId = userId; }
    public BigDecimal getTotalAmount() { return totalAmount; }
    public void setTotalAmount(BigDecimal totalAmount) { this.totalAmount = totalAmount; }
    public BigDecimal getDiscountAmount() { return discountAmount; }
    public void setDiscountAmount(BigDecimal discountAmount) { this.discountAmount = discountAmount; }
    public BigDecimal getPaidAmount() { return paidAmount; }
    public void setPaidAmount(BigDecimal paidAmount) { this.paidAmount = paidAmount; }
    public BigDecimal getChangeAmount() { return changeAmount; }
    public void setChangeAmount(BigDecimal changeAmount) { this.changeAmount = changeAmount; }
    public Integer getPaymentMethod() { return paymentMethod; }
    public void setPaymentMethod(Integer paymentMethod) { this.paymentMethod = paymentMethod; }
    public Integer getOrderStatus() { return orderStatus; }
    public void setOrderStatus(Integer orderStatus) { this.orderStatus = orderStatus; }
    public String getRemark() { return remark; }
    public void setRemark(String remark) { this.remark = remark; }
    public String getCreateTime() { return createTime; }
    public void setCreateTime(String createTime) { this.createTime = createTime; }
    public String getRealName() { return realName; }
    public void setRealName(String realName) { this.realName = realName; }
    public Integer getDetailCount() { return detailCount; }
    public void setDetailCount(Integer detailCount) { this.detailCount = detailCount; }
}

package com.supermarket.mapper;

import com.supermarket.entity.SalesOrder;
import org.apache.ibatis.annotations.Param;

import java.util.List;

/**
 * 销售订单 Mapper — 订单 CRUD + 销售汇总 + 视图查询
 * <p>
 * 关键 SQL：
 * - selectPage：LEFT JOIN sys_user 联表查收银员姓名，子查询统计商品种类数
 * - selectTodaySummary：DATE(create_time)=CURDATE() 聚合当日数据
 * - selectSalesReport：查询视图 v_sales_summary 获取按天汇总的销售日报
 * </p>
 */
public interface SalesOrderMapper {

    /**
     * 创建订单，useGeneratedKeys=true 自动回填 orderId
     */
    int insert(SalesOrder order);

    /**
     * 分页查询订单（联表：sys_user 获取收银员姓名，子查询统计明细种类数）
     */
    List<SalesOrder> selectPage(@Param("keyword") String keyword,
                                @Param("offset") Integer offset,
                                @Param("limit") Integer limit);

    int count(@Param("keyword") String keyword);

    SalesOrder selectById(Integer orderId);

    /**
     * 今日销售汇总：COUNT(*) 订单数 + SUM(paid_amount) 今日销售额
     */
    java.util.Map<String, Object> selectTodaySummary();

    /**
     * 查询销售日报视图 v_sales_summary（sale_date, order_count, total_sales, total_quantity）
     */
    java.util.List<java.util.Map<String, Object>> selectSalesReport();

    /**
     * 退款：将订单状态改为 2（已退款）
     */
    int updateOrderStatus(@Param("orderId") Integer orderId,
                          @Param("orderStatus") Integer orderStatus);
}

package com.supermarket.service.impl;

import com.supermarket.entity.Product;
import com.supermarket.entity.SalesDetail;
import com.supermarket.entity.SalesOrder;
import com.supermarket.mapper.ProductMapper;
import com.supermarket.mapper.SalesDetailMapper;
import com.supermarket.mapper.SalesOrderMapper;
import com.supermarket.service.SalesService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import org.springframework.beans.factory.annotation.Autowired;
import java.math.BigDecimal;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * 销售Service实现 — 核心业务：订单提交（事务）、查询、退款
 * <p>
 * submitOrder 是整个系统最核心的业务方法，使用 @Transactional 保证
 * "订单保存 → 明细保存 → 库存扣减" 三个操作的原子性。
 * 订单编号格式：SO + yyyyMMddHHmmss（如 SO20260624143001）。
 * </p>
 */
@Service
public class SalesServiceImpl implements SalesService {

    @Autowired
    private SalesOrderMapper salesOrderMapper;
    @Autowired
    private SalesDetailMapper salesDetailMapper;
    @Autowired
    private ProductMapper productMapper;

    /**
     * 提交销售订单（事务方法）
     * <p>
     * 五步流程：
     * 1. 生成订单编号 (SO + 时间戳)
     * 2. 遍历明细，校验商品存在 & 库存充足，计算小计和总金额
     * 3. 插入 sales_order 主记录
     * 4. 批量插入 sales_detail 明细
     * 5. 扣减 product 库存
     * </p>
     *
     * @param order   订单主信息（userId/paymentMethod 需预先设置）
     * @param details 明细列表（每个元素含 productId/quantity）
     * @return success=true 时包含 orderId 和 orderNo
     */
    @Override
    @Transactional  // 事务：保证订单和明细、库存要么全成功，要么全回滚
    public Map<String, Object> submitOrder(SalesOrder order, List<SalesDetail> details) {
        Map<String, Object> result = new HashMap<>();

        // 1. 生成订单编号
        String orderNo = "SO" + new SimpleDateFormat("yyyyMMddHHmmss").format(new Date());
        order.setOrderNo(orderNo);

        // 2. 计算总金额
        BigDecimal total = BigDecimal.ZERO;
        for (SalesDetail detail : details) {
            Product p = productMapper.selectById(detail.getProductId());
            if (p == null) {
                result.put("success", false);
                result.put("msg", "商品不存在");
                return result;
            }
            if (p.getStock() < detail.getQuantity()) {
                result.put("success", false);
                result.put("msg", "商品[" + p.getProductName() + "]库存不足，当前库存：" + p.getStock());
                return result;
            }
            BigDecimal subtotal = p.getPrice().multiply(new BigDecimal(detail.getQuantity()));
            detail.setProductName(p.getProductName());
            detail.setPrice(p.getPrice());
            detail.setSubtotal(subtotal);
            total = total.add(subtotal);
        }
        order.setTotalAmount(total);
        if (order.getDiscountAmount() == null) {
            order.setDiscountAmount(BigDecimal.ZERO);
        }

        // 3. 保存订单
        salesOrderMapper.insert(order);

        // 4. 保存明细
        for (SalesDetail detail : details) {
            detail.setOrderId(order.getOrderId());
        }
        salesDetailMapper.batchInsert(details);

        // 5. 扣减库存
        for (SalesDetail detail : details) {
            productMapper.updateStock(detail.getProductId(), -detail.getQuantity());
        }

        result.put("success", true);
        result.put("msg", "订单提交成功");
        result.put("orderId", order.getOrderId());
        result.put("orderNo", orderNo);
        return result;
    }

    /**
     * 订单分页查询（含收银员姓名、商品种类数）
     *
     * @param keyword 订单号搜索关键词（可选）
     * @param page    页码
     * @param limit   每页条数
     */
    @Override
    public Map<String, Object> getOrderPage(String keyword, Integer page, Integer limit) {
        Map<String, Object> result = new HashMap<>();
        int offset = (page - 1) * limit;
        result.put("list", salesOrderMapper.selectPage(keyword, offset, limit));
        result.put("total", salesOrderMapper.count(keyword));
        return result;
    }

    @Override
    public Map<String, Object> getOrderDetail(Integer orderId) {
        Map<String, Object> result = new HashMap<>();
        SalesOrder order = salesOrderMapper.selectById(orderId);
        List<SalesDetail> details = salesDetailMapper.selectByOrderId(orderId);
        result.put("order", order);
        result.put("details", details);
        return result;
    }

    @Override
    public Map<String, Object> getTodaySummary() {
        return salesOrderMapper.selectTodaySummary();
    }

    @Override
    public List<Map<String, Object>> getSalesReport() {
        return salesOrderMapper.selectSalesReport();
    }

    @Override
    public boolean refund(Integer orderId) {
        SalesOrder order = salesOrderMapper.selectById(orderId);
        if (order == null || order.getOrderStatus() != 1) {
            return false;
        }
        salesOrderMapper.updateOrderStatus(orderId, 2);
        return true;
    }
}

package com.supermarket.service.impl;

import com.supermarket.entity.SysUser;
import com.supermarket.mapper.SysUserMapper;
import com.supermarket.service.SysUserService;
import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Service;
import org.springframework.web.context.request.RequestContextHolder;
import org.springframework.web.context.request.ServletRequestAttributes;

import org.springframework.beans.factory.annotation.Autowired;
import java.util.HashMap;
import java.util.Map;

/**
 * 用户Service实现 — 负责登录认证、注册、会话管理
 * <p>
 * 使用 HttpSession 管理登录状态（替代初版 ThreadLocal），
 * 确保同一浏览器会话内多个HTTP请求共享登录信息。
 * </p>
 */
@Service
public class SysUserServiceImpl implements SysUserService {

    @Autowired
    private SysUserMapper sysUserMapper;

    /**
     * 获取当前请求的 HttpSession，用于存取登录用户
     */
    private HttpSession getSession() {
        ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.currentRequestAttributes();
        return attrs.getRequest().getSession();
    }

    /**
     * 登录：校验用户名密码，成功后将用户存入 Session
     *
     * @param username 用户名
     * @param password 明文密码（生产环境应使用 BCrypt 加密）
     * @return success=true 时包含 user 对象
     */
    @Override
    public Map<String, Object> login(String username, String password) {
        Map<String, Object> result = new HashMap<>();
        SysUser user = sysUserMapper.selectByUsernameAndPassword(username, password);
        if (user == null) {
            result.put("success", false);
            result.put("msg", "用户名或密码错误");
            return result;
        }
        getSession().setAttribute("loginUser", user);
        result.put("success", true);
        result.put("msg", "登录成功");
        result.put("user", user);
        return result;
    }

    /**
     * 注册：检查用户名唯一性后插入新用户
     *
     * @param user 新用户实体（含 username/password/realName/roleType）
     * @return true=注册成功，false=用户名已存在
     */
    @Override
    public boolean register(SysUser user) {
        SysUser exist = sysUserMapper.selectByUsername(user.getUsername());
        if (exist != null) {
            return false;
        }
        sysUserMapper.insert(user);
        return true;
    }

    /**
     * 获取当前登录用户（从 Session 中读取）
     *
     * @return 登录用户对象，未登录返回 null
     */
    @Override
    public SysUser getLoginUser() {
        try {
            HttpSession session = ((ServletRequestAttributes) RequestContextHolder.currentRequestAttributes()).getRequest().getSession();
            return (SysUser) session.getAttribute("loginUser");
        } catch (Exception e) {
            return null;
        }
    }

    /**
     * 退出登录：清除 Session 中的用户信息
     */
    @Override
    public void logout() {
        getSession().removeAttribute("loginUser");
    }

    /**
     * 修改密码：校验原密码正确后更新
     */
    @Override
    public boolean updatePassword(Integer userId, String oldPassword, String newPassword) {
        SysUser user = sysUserMapper.selectById(userId);
        if (user == null || !user.getPassword().equals(oldPassword)) {
            return false;
        }
        sysUserMapper.updatePassword(userId, newPassword);
        return true;
    }
}
